// $getWorkflowStaticData is only available in Code nodes, so read the
// watermark here and hand since_id to the HTTP node as item data.
const sd = $getWorkflowStaticData('global');
return [{ json: { since_id: sd.proposalsLastId || 0 } }];

// Advance the watermark past every note seen, then fan out one item per
// candidate next-step. No candidates => no downstream items (loop idles).
const data = $input.first().json;
const sd = $getWorkflowStaticData('global');
if (typeof data.max_id === 'number' && data.max_id > (sd.proposalsLastId || 0)) {
  sd.proposalsLastId = data.max_id;
}
return (data.candidates || []).map((c) => ({ json: c }));

// One local-model classification prompt per candidate next-step.
return $input.all().map((it) => {
  const c = it.json;
  const prompt = [
    'You classify a single meeting NEXT-STEP. Decide if acting on it requires drafting a business PROPOSAL (partnership, client/SOW, pricing, or M&A).',
    'NOT proposals: scheduling/calendar, internal research, data pulls, simple replies or follow-ups, status updates.',
    '',
    'Meeting: ' + (c.meeting_title || ''),
    'Summary: ' + (c.summary || ''),
    'Next-step: ' + (c.step_title || ''),
    (c.step_text || ''),
    '',
    'Return ONLY JSON: {"is_proposal": true|false, "confidence": 0.0-1.0, "entity": "<slug or null>", "why": "<short>"}'
  ].join('\n');
  return { json: { ...c, model: 'qwen3:4b-instruct', prompt } };
});

// Pair each qwen3 response with its candidate (1:1 by index) and parse the
// JSON verdict. Build the self-contained proposal task body here too.
return $input.all().map((it, i) => {
  const src = $('Build Gate Prompt').all()[i].json;
  let v = {};
  try { v = JSON.parse(it.json.response || it.json.text || '{}'); } catch (e) { v = {}; }
  const entity = v.entity || src.entity || '';
  const task_body = [
    'Draft a business proposal for this meeting next-step.',
    '',
    'Meeting: ' + (src.meeting_title || ''),
    'Summary: ' + (src.summary || ''),
    'Entity: ' + entity,
    'Owners: ' + ((src.owners || []).join(', ')),
    '',
    'Next-step: ' + (src.step_title || ''),
    (src.step_text || ''),
    '',
    "Recall the closest example from gbrain source 'proposal-templates' and follow its structure. Produce a versioned markdown DRAFT (no send); mark anything needing human approval or legal review. Emit run-metadata: artifact, proposal_title, entity, recommendation."
  ].join('\n');
  return { json: {
    meeting_id: src.meeting_id,
    step_index: src.step_index,
    step_title: src.step_title,
    is_proposal: v.is_proposal === true,
    confidence: Number(v.confidence) || 0,
    entity,
    why: v.why || '',
    task_body
  } };
});
